#!/usr/bin/env bash
# =============================================================================
#  mac_repair.sh — Comprehensive macOS Repair & Optimization Script
#  Target : MacBook Pro 16" M3 Max · 36 GB RAM · 1 TB SSD
#  Author : Generated by Antigravity AI
#  Date   : 2026-03-09
# =============================================================================
# Usage:
#   chmod +x mac_repair.sh
#   sudo ./mac_repair.sh            # Full run (some modules need sudo)
#   ./mac_repair.sh --no-sudo       # Skip modules that require root
#   ./mac_repair.sh --dry-run       # Analyse only, apply no fixes
#   ./mac_repair.sh --module disk   # Run a single module
# =============================================================================

# Intentionally NOT using set -e or set -o pipefail:
# Diagnostic scripts run many commands that legitimately return non-zero
# (grep with no match, find on protected dirs, xattr on system files, etc.).
# pipefail in particular causes '|| fallback' patterns in pipelines to fire
# even when intermediate steps succeed, corrupting numeric captures.
set -u
IFS=$'\n\t'

# ── Version ──────────────────────────────────────────────────────────────────
SCRIPT_VERSION="2.0.0"
SCRIPT_NAME="mac_repair"

# ── CLI flags ─────────────────────────────────────────────────────────────────
DRY_RUN=false
NO_SUDO=false
SINGLE_MODULE=""

for arg in "$@"; do
  case "$arg" in
    --dry-run)    DRY_RUN=true ;;
    --no-sudo)    NO_SUDO=true ;;
    --module=*)   SINGLE_MODULE="${arg#*=}" ;;
    -h|--help)
      echo "Usage: sudo ./mac_repair.sh [--dry-run] [--no-sudo] [--module=<name>]"
      echo "Modules: system | disk | permissions | launchd | network | prefs | security | performance | cache | logs"
      exit 0 ;;
  esac
done

# ── Paths ─────────────────────────────────────────────────────────────────────
TIMESTAMP=$(date '+%Y%m%d_%H%M%S')
LOG_DIR="$HOME/Desktop/mac_repair_logs"
LOG_FILE="$LOG_DIR/${SCRIPT_NAME}_${TIMESTAMP}.log"
REPORT_FILE="$LOG_DIR/${SCRIPT_NAME}_report_${TIMESTAMP}.md"

mkdir -p "$LOG_DIR"

# ── Colours ───────────────────────────────────────────────────────────────────
if [[ -t 1 ]]; then
  RED='\033[0;31m'; YELLOW='\033[1;33m'; GREEN='\033[0;32m'
  CYAN='\033[0;36m';  BOLD='\033[1m';   RESET='\033[0m'
  BLUE='\033[0;34m'; MAGENTA='\033[0;35m'; WHITE='\033[1;37m'
else
  RED=''; YELLOW=''; GREEN=''; CYAN=''; BOLD=''; RESET=''; BLUE=''; MAGENTA=''; WHITE=''
fi

# ── Counters ──────────────────────────────────────────────────────────────────
TOTAL_ISSUES=0
TOTAL_FIXED=0
TOTAL_WARNINGS=0

# ── Report accumulator ────────────────────────────────────────────────────────
REPORT_LINES=()

# =============================================================================
# HELPERS
# =============================================================================

log_raw() { echo -e "$*" | tee -a "$LOG_FILE"; }

header() {
  local title="$1"
  local bar
  bar=$(printf '═%.0s' {1..70})
  log_raw ""
  log_raw "${BOLD}${CYAN}╔${bar}╗${RESET}"
  log_raw "${BOLD}${CYAN}║  ⬡  ${title}$(printf '%*s' $((62 - ${#title})) '')║${RESET}"
  log_raw "${BOLD}${CYAN}╚${bar}╝${RESET}"
  REPORT_LINES+=("## $title")
}

section() { log_raw "${BOLD}${BLUE}▸ $*${RESET}"; REPORT_LINES+=("### $*"); }

ok()   { log_raw "  ${GREEN}✔${RESET}  $*";  REPORT_LINES+=("- ✅ $*"); }
warn() { log_raw "  ${YELLOW}⚠${RESET}  $*"; REPORT_LINES+=("- ⚠️  $*"); ((TOTAL_WARNINGS++)) || true; }
err()  {
  log_raw "  ${RED}✖${RESET}  $*"
  REPORT_LINES+=("- ❌ $*")
  ((TOTAL_ISSUES++)) || true
}
fixed(){ log_raw "  ${GREEN}⟳${RESET}  ${GREEN}FIXED:${RESET} $*"; REPORT_LINES+=("- 🔧 FIXED: $*"); ((TOTAL_FIXED++)) || true; }
info() { log_raw "  ${MAGENTA}ℹ${RESET}  $*";  REPORT_LINES+=("- ℹ️  $*"); }
skip() { log_raw "  ${WHITE}↷${RESET}  ${WHITE}SKIP:${RESET} $*"; }

run_fix() {
  # run_fix "description" command args...
  local desc="$1"; shift
  if $DRY_RUN; then
    skip "[DRY-RUN] Would run: $*"
  else
    if "$@" >> "$LOG_FILE" 2>&1; then
      fixed "$desc"
    else
      warn "Fix attempted but returned non-zero: $desc"
    fi
  fi
}

need_sudo() {
  if $NO_SUDO; then
    skip "Skipped (--no-sudo): $*"
    return 1
  fi
  if [[ $EUID -ne 0 ]]; then
    warn "Root required for: $* — re-run with sudo"
    return 1
  fi
  return 0
}

# Write markdown report
flush_report() {
  {
    echo "# macOS Repair Report"
    echo ""
    echo "> Generated: $(date)"
    echo "> Script version: $SCRIPT_VERSION"
    echo "> Host: $(hostname)"
    echo "> macOS: $(sw_vers -productVersion) $(sw_vers -buildVersion)"
    echo ""
    echo "| Metric | Count |"
    echo "|--------|-------|"
    echo "| ❌ Issues found | $TOTAL_ISSUES |"
    echo "| 🔧 Auto-fixed   | $TOTAL_FIXED  |"
    echo "| ⚠️  Warnings     | $TOTAL_WARNINGS |"
    echo ""
    for line in "${REPORT_LINES[@]}"; do
      echo "$line"
    done
  } > "$REPORT_FILE"
}

# Check if a module should run
should_run() {
  [[ -z "$SINGLE_MODULE" ]] || [[ "$SINGLE_MODULE" == "$1" ]]
}

# =============================================================================
# BANNER
# =============================================================================

print_banner() {
  clear
  log_raw "${BOLD}${CYAN}"
  log_raw "  ╔══════════════════════════════════════════════════════════╗"
  log_raw "  ║          🍎  mac_repair.sh  v${SCRIPT_VERSION}                    ║"
  log_raw "  ║    MacBook Pro 16\" M3 Max · Apple Silicon Optimised     ║"
  log_raw "  ╚══════════════════════════════════════════════════════════╝"
  log_raw "${RESET}"
  log_raw "  ${BOLD}Log    :${RESET} $LOG_FILE"
  log_raw "  ${BOLD}Report :${RESET} $REPORT_FILE"
  log_raw "  ${BOLD}Mode   :${RESET} $( $DRY_RUN && echo 'DRY-RUN (no changes)' || echo 'LIVE (fixes applied)' )"
  log_raw ""
}

# =============================================================================
# MODULE 1 — SYSTEM INFORMATION
# =============================================================================

module_system_info() {
  should_run "system" || return 0
  header "MODULE 1 · System Information & Preflight"

  section "Hardware overview"
  local macos cpu ram ssd chip model serial
  macos="$(sw_vers -productName) $(sw_vers -productVersion) ($(sw_vers -buildVersion))"
  chip=$(sysctl -n machdep.cpu.brand_string 2>/dev/null || echo "Unknown")
  ram=$(( $(sysctl -n hw.memsize) / 1024 / 1024 / 1024 ))
  model=$(system_profiler SPHardwareDataType 2>/dev/null | awk '/Model Name/{print $NF; exit}')
  serial=$(system_profiler SPHardwareDataType 2>/dev/null | awk '/Serial Number/{print $NF; exit}')

  info "macOS  : $macos"
  info "Chip   : $chip"
  info "RAM    : ${ram} GB"
  info "Model  : $model ($serial)"
  info "Uptime : $(uptime | awk '{print $3, $4}' | tr -d ',')"
  info "User   : $(whoami)  (EUID=$EUID)"
  info "Date   : $(date)"

  section "macOS version sanity"
  local major
  major=$(sw_vers -productVersion | cut -d. -f1)
  if (( major >= 14 )); then
    ok "macOS $major — Sonoma or newer (Apple Silicon supported)"
  elif (( major == 13 )); then
    ok "macOS Ventura — supported"
  else
    warn "macOS version may be outdated ($major). Consider upgrading."
  fi

  section "Rosetta 2 status"
  if /usr/bin/pgrep oahd &>/dev/null; then
    info "Rosetta 2 is running (oahd active)"
  else
    ok "Rosetta 2 not actively needed (native Apple Silicon mode)"
  fi

  section "FileVault status"
  local fv_status
  fv_status=$(fdesetup status 2>/dev/null)
  if echo "$fv_status" | grep -q "FileVault is On"; then
    ok "FileVault: Enabled ✔"
  else
    warn "FileVault: $fv_status — encryption is recommended"
  fi

  section "SIP (System Integrity Protection)"
  local sip_status
  sip_status=$(csrutil status 2>/dev/null || echo "unknown")
  if echo "$sip_status" | grep -q "enabled"; then
    ok "SIP: Enabled ✔"
  else
    err "SIP: DISABLED — system is more vulnerable. Re-enable from Recovery Mode."
  fi

  section "Battery health"
  if command -v system_profiler &>/dev/null; then
    local batt_info cycle_count max_cap condition
    batt_info=$(system_profiler SPPowerDataType 2>/dev/null)
    cycle_count=$(echo "$batt_info" | awk '/Cycle Count/{print $NF}')
    max_cap=$(echo "$batt_info" | awk '/Maximum Capacity/{print $NF}')
    condition=$(echo "$batt_info" | awk '/Condition/{print $NF}')
    [[ -n "$cycle_count" ]] && info "Battery cycle count : $cycle_count"
    [[ -n "$max_cap"    ]] && info "Battery max capacity: $max_cap"
    if [[ "$condition" == "Normal" ]]; then
      ok "Battery condition: Normal"
    elif [[ -n "$condition" ]]; then
      warn "Battery condition: $condition — monitor closely"
    fi
  fi
}

# =============================================================================
# MODULE 2 — DISK HEALTH & FILESYSTEM
# =============================================================================

module_disk() {
  should_run "disk" || return 0
  header "MODULE 2 · Disk Health & Filesystem"

  section "Disk usage"
  local disk_info
  disk_info=$(df -H / 2>/dev/null | tail -1)
  local used avail pct raw_pct
  used=$(echo "$disk_info" | awk '{print $3}')
  avail=$(echo "$disk_info" | awk '{print $4}')
  raw_pct=$(echo "$disk_info" | awk '{print $5}' | tr -d '% \n')
  pct=$(echo "${raw_pct:-0}" | grep -o '^[0-9]\+' || echo 0)
  
  info "Boot volume — Used: $used | Free: $avail | ${pct}% used"

  if (( pct >= 95 )); then
    err "Disk critically full (${pct}%). macOS needs ≥10% free for swap and virtual memory."
  elif (( pct >= 85 )); then
    warn "Disk usage high (${pct}%). Consider freeing space."
  else
    ok "Disk usage acceptable (${pct}%)"
  fi

  section "SMART status"
  if command -v diskutil &>/dev/null; then
    local smart
    smart=$(diskutil info / 2>/dev/null | awk '/SMART Status/{print $NF}')
    if [[ "$smart" == "Verified" ]]; then
      ok "SMART status: Verified"
    else
      err "SMART status: $smart — potential hardware issue!"
    fi
  fi

  section "APFS volume integrity — Verify"
  # NOTE: diskutil repairVolume on a *mounted* container is unsupported by macOS.
  # We run verifyVolume (read-only, safe) and advise Recovery for actual repair.
  local container_disk
  container_disk=$(diskutil info / 2>/dev/null | awk '/APFS Container/{print $NF}' || true)
  if [[ -n "$container_disk" ]]; then
    info "Verifying APFS container: $container_disk (read-only — safe on live system)"
    if $DRY_RUN; then
      skip "[DRY-RUN] diskutil verifyVolume $container_disk"
    else
      local verify_out
      verify_out=$(diskutil verifyVolume "$container_disk" 2>&1 || true)
      if echo "$verify_out" | grep -qi "appears to be OK\|succeeded\|filesystem check exit code is 0"; then
        fixed "APFS verify passed on $container_disk"
      else
        warn "APFS verify found issues. Run First Aid from Recovery Mode:"
        warn "  Shut down → Hold Power → Disk Utility → First Aid on $container_disk"
        echo "$verify_out" | head -10 | while read -r line; do info "    $line"; done
      fi
    fi
  else
    warn "Could not determine APFS container disk — skipping verify"
  fi

  section "Disk permissions repair (macOS 10.11+: limited scope)"
  # Since El Capitan, diskutil repairPermissions only works on certain areas
  if command -v diskutil &>/dev/null; then
    info "Note: diskutil repairPermissions is deprecated on modern macOS (SIP manages system permissions)"
    ok "System directory permissions managed by SIP"
  fi

  section "Extraneous extended attributes on home folder"
  local xattr_count=0
  # Run in a subshell to isolate any pipe failures; extract only the integer
  xattr_count=$(xattr -r "$HOME" 2>/dev/null | wc -l 2>/dev/null) || xattr_count=0
  xattr_count=$(echo "$xattr_count" | tr -d ' \n' || echo 0)
  [[ "$xattr_count" =~ ^[0-9]+$ ]] || xattr_count=0
  info "Extended attributes found in home: $xattr_count"
  if (( xattr_count > 500 )); then
    warn "High number of extended attributes. Consider auditing with: xattr -r $HOME"
  else
    ok "Extended attribute count looks normal ($xattr_count)"
  fi

  section "Broken symlinks in /usr/local"
  local broken_links=()
  while IFS= read -r link; do
    [[ -n "$link" ]] && broken_links+=("$link")
  done < <(find /usr/local -xtype l 2>/dev/null || true)
  if (( ${#broken_links[@]} > 0 )); then
    warn "Found ${#broken_links[@]} broken symlinks in /usr/local:"
    for bl in "${broken_links[@]}"; do
      warn "  → $bl"
    done
  else
    ok "No broken symlinks found in /usr/local"
  fi

  section "Large files (>500 MB) — top consumers"
  find "$HOME" -maxdepth 6 -type f -size +500M 2>/dev/null | head -20 | while read -r f; do
    local sz
    sz=$(du -sh "$f" 2>/dev/null | cut -f1)
    info "  $sz  $f"
  done || true

  section "Trash size"
  local trash_size
  trash_size=$(du -sh "$HOME/.Trash" 2>/dev/null | cut -f1 || echo "0B")
  info "Trash size: $trash_size"
  if [[ "$trash_size" != "0B" && "$trash_size" != "  0B" ]]; then
    warn "Trash not empty ($trash_size). Empty it to reclaim space."
  fi
}

# =============================================================================
# MODULE 3 — LAUNCH AGENTS & DAEMONS AUDIT
# =============================================================================

module_launchd() {
  should_run "launchd" || return 0
  header "MODULE 3 · LaunchAgents & LaunchDaemons Audit"

  local LAUNCH_PATHS=(
    "/Library/LaunchDaemons"
    "/Library/LaunchAgents"
    "$HOME/Library/LaunchAgents"
    "/System/Library/LaunchDaemons"
    "/System/Library/LaunchAgents"
  )

  section "Scanning all plist files in launch directories"
  local plist_issues=0

  for dir in "${LAUNCH_PATHS[@]}"; do
    [[ -d "$dir" ]] || continue
    section "  Directory: $dir"
    while IFS= read -r plist; do
      local label=""
      local valid=true

      # Check well-formedness
      if ! plutil -lint "$plist" >> "$LOG_FILE" 2>&1; then
        err "Malformed plist: $plist"
        ((plist_issues++)) || true
        valid=false
      fi

      # Get label
      label=$(defaults read "$plist" Label 2>/dev/null || echo "(no label)")

      # Check if Program/ProgramArguments executable exists
      local prog
      prog=$(defaults read "$plist" Program 2>/dev/null || \
             defaults read "$plist" ProgramArguments 2>/dev/null | \
             grep -o '"[^"]*"' | head -1 | tr -d '"' || echo "")
      if [[ -n "$prog" ]] && [[ ! -e "$prog" ]]; then
        warn "  [$label] Program not found: $prog"
        ((plist_issues++)) || true
      fi

      $valid && ok "  [$label] → $(basename "$plist")"
    done < <(find "$dir" -name "*.plist" -maxdepth 1 2>/dev/null)
  done

  if (( plist_issues == 0 )); then
    ok "All LaunchAgent/Daemon plists are valid"
  else
    warn "Found $plist_issues plist issues"
  fi

  section "Currently loaded user launch agents (non-Apple)"
  launchctl list 2>/dev/null | awk 'NR>1 && $3 !~ /^com\.apple\./ && $3 !~ /^0$/ {print "  " $0}' | head -40 | while IFS= read -r line; do
    [[ -n "$line" ]] && info "$line"
  done || true

  section "Checking for known adware / malicious launch agents"
  local KNOWN_MALWARE=(
    "com.pckeeper" "com.iminent" "com.zeobit" "com.mackeeper"
    "com.akamaihd" "com.genieo" "com.conduit" "com.mcp"
    "com.cleverfiles" "com.weknow" "com.yontoo" "com.spigot"
    "io.macpaw" "com.crossrider" "com.perion" "com.bncore"
  )
  local found_malware=false
  for dir in "${LAUNCH_PATHS[@]}"; do
    [[ -d "$dir" ]] || continue
    for pattern in "${KNOWN_MALWARE[@]}"; do
      while IFS= read -r f; do
        err "Suspicious launch item: $f (matches: $pattern)"
        found_malware=true
      done < <(find "$dir" -name "*${pattern}*" 2>/dev/null)
    done
  done
  $found_malware || ok "No known adware/malware launch items found"
}

# =============================================================================
# MODULE 4 — NETWORK DIAGNOSTICS
# =============================================================================

module_network() {
  should_run "network" || return 0
  header "MODULE 4 · Network Diagnostics"

  section "Active network interfaces"
  ifconfig 2>/dev/null | awk '/^[a-z]/{iface=$1} /inet /{print "  " iface, $2}' | grep -v '127.0.0.1' || true

  section "DNS configuration"
  local dns_servers
  dns_servers=$(scutil --dns 2>/dev/null | awk '/nameserver\[/{print $3}' | sort -u)
  if [[ -n "$dns_servers" ]]; then
    info "DNS servers:"
    echo "$dns_servers" | while read -r ns; do info "  → $ns"; done
    # Warn about unusual or overridden DNS
    if echo "$dns_servers" | grep -qE "^(8\.8\.|1\.1\.|9\.9\.9\.)"; then
      ok "DNS includes well-known resolvers"
    fi
  else
    warn "No DNS servers detected"
  fi

  section "Proxy settings"
  local proxy_info
  proxy_info=$(scutil --proxy 2>/dev/null)
  if echo "$proxy_info" | grep -qi "Enable.*1"; then
    warn "Proxy is ENABLED — verify this is intentional:"
    echo "$proxy_info" | grep -i "enable\|server\|port" | while read -r line; do warn "  $line"; done
  else
    ok "No active proxy detected"
  fi

  section "Connectivity test"
  local sites=("www.apple.com" "www.google.com" "1.1.1.1")
  for site in "${sites[@]}"; do
    if ping -c 1 -W 2 "$site" &>/dev/null; then
      ok "Reachable: $site"
    else
      warn "Unreachable: $site"
    fi
  done

  section "DNS resolution test"
  for domain in "apple.com" "icloud.com"; do
    if dscacheutil -q host -a name "$domain" &>/dev/null; then
      ok "DNS resolves: $domain"
    else
      warn "DNS failed for: $domain"
    fi
  done

  section "Network preference files"
  local net_prefs=(
    "/Library/Preferences/SystemConfiguration/preferences.plist"
    "/Library/Preferences/SystemConfiguration/NetworkInterfaces.plist"
    "/Library/Preferences/SystemConfiguration/com.apple.airport.preferences.plist"
  )
  for pref in "${net_prefs[@]}"; do
    [[ -f "$pref" ]] || continue
    if plutil -lint "$pref" >> "$LOG_FILE" 2>&1; then
      ok "Valid: $(basename "$pref")"
    else
      err "Corrupt: $pref"
    fi
  done

  section "Hosts file anomalies"
  local hosts_entries
  hosts_entries=$(grep -vE '^(#|$|\s+$)' /etc/hosts 2>/dev/null | grep -v '127.0.0.1\|::1\|localhost\|broadcasthost' || true)
  if [[ -n "$hosts_entries" ]]; then
    warn "Non-standard entries in /etc/hosts:"
    echo "$hosts_entries" | while read -r line; do warn "  $line"; done
  else
    ok "/etc/hosts looks clean"
  fi

  section "ARP cache"
  arp -a 2>/dev/null | head -10 | while read -r line; do info "  $line"; done

  section "Open network ports (listening)"
  info "Listening services (lsof):"
  lsof -nP -iTCP -sTCP:LISTEN 2>/dev/null | awk 'NR>1 {print "  " $1, $8, $9}' | sort -u | head -30 | while read -r line; do
    info "$line"
  done || true
}

# =============================================================================
# MODULE 5 — SYSTEM PREFERENCES & PLIST CORRUPTION
# =============================================================================

module_prefs() {
  should_run "prefs" || return 0
  header "MODULE 5 · System Preferences & Plist Integrity"

  local PREF_DIRS=(
    "$HOME/Library/Preferences"
    "/Library/Preferences"
  )

  section "Scanning user preference plists"
  local bad_plists=0 total_plists=0

  for pref_dir in "${PREF_DIRS[@]}"; do
    [[ -d "$pref_dir" ]] || continue
    while IFS= read -r pfile; do
      ((total_plists++)) || true
      if ! plutil -lint "$pfile" >> "$LOG_FILE" 2>&1; then
        err "Corrupt plist: $pfile"
        ((bad_plists++)) || true
        if need_sudo "Remove corrupt plist"; then
          if ! $DRY_RUN; then
            local backup="${pfile}.bak_${TIMESTAMP}"
            cp "$pfile" "$backup" 2>/dev/null || true
            rm -f "$pfile"
            fixed "Removed corrupt plist (backed up): $pfile → $backup"
          else
            skip "[DRY-RUN] Would remove: $pfile"
          fi
        fi
      fi
    done < <(find "$pref_dir" -name "*.plist" -maxdepth 2 2>/dev/null)
  done

  info "Scanned $total_plists prefs, found $bad_plists corrupted"
  (( bad_plists == 0 )) && ok "All preference plists are valid"

  section "Critical Apple preference files"
  local CRITICAL_PREFS=(
    "$HOME/Library/Preferences/com.apple.finder.plist"
    "$HOME/Library/Preferences/com.apple.dock.plist"
    "$HOME/Library/Preferences/com.apple.systempreferences.plist"
    "$HOME/Library/Preferences/com.apple.screensaver.plist"
    "$HOME/Library/Preferences/com.apple.spaces.plist"
    "$HOME/Library/Preferences/com.apple.universalaccess.plist"
    "/Library/Preferences/com.apple.loginwindow.plist"
  )

  for pref in "${CRITICAL_PREFS[@]}"; do
    [[ -f "$pref" ]] || continue
    local name
    name=$(basename "$pref")
    if plutil -lint "$pref" >> "$LOG_FILE" 2>&1; then
      ok "$name — valid"
    else
      err "$name — CORRUPT"
      warn "Resetting $name to defaults"
      if ! $DRY_RUN; then
        local backup="${pref}.bak_${TIMESTAMP}"
        cp "$pref" "$backup" || true
        rm -f "$pref"
        fixed "Reset $name (backup at $backup)"
      fi
    fi
  done

  section "Finder preferences check"
  local show_hidden
  show_hidden=$(defaults read com.apple.finder AppleShowAllFiles 2>/dev/null || echo "0")
  info "Finder show hidden files: $( [[ "$show_hidden" == "1" || "$show_hidden" == "YES" ]] && echo 'ON' || echo 'OFF' )"

  section "Dock preferences check"
  local autohide
  autohide=$(defaults read com.apple.dock autohide 2>/dev/null || echo "0")
  info "Dock autohide: $( [[ "$autohide" == "1" ]] && echo 'ON' || echo 'OFF' )"

  section "Login window settings"
  if [[ -f "/Library/Preferences/com.apple.loginwindow.plist" ]]; then
    local guest_enabled
    guest_enabled=$(defaults read /Library/Preferences/com.apple.loginwindow GuestEnabled 2>/dev/null || echo "0")
    if [[ "$guest_enabled" == "1" ]]; then
      warn "Guest account is ENABLED"
    else
      ok "Guest account is disabled"
    fi
  fi
}

# =============================================================================
# MODULE 6 — SECURITY AUDIT
# =============================================================================

module_security() {
  should_run "security" || return 0
  header "MODULE 6 · Security Audit"

  section "sudoers file integrity"
  if need_sudo "visudo -c"; then
    if visudo -c >> "$LOG_FILE" 2>&1; then
      ok "sudoers file is valid"
    else
      err "sudoers file has errors — DO NOT EDIT blindly, use visudo"
    fi
    # Check for unusual sudoers includes
    if grep -rE "NOPASSWD" /etc/sudoers /etc/sudoers.d/ 2>/dev/null | grep -v "^#" | grep -v "^/etc/sudoers.d/ does not exist"; then
      warn "NOPASSWD entries found in sudoers — audit carefully"
    fi
  fi

  section "Authorisation database anomalies"
  if need_sudo "security authorizationdb"; then
    security authorizationdb read system.login.console >> "$LOG_FILE" 2>/dev/null || true
    ok "Authorization database readable"
  fi

  section "SSH keys and authorized_keys"
  local ssh_dir="$HOME/.ssh"
  if [[ -d "$ssh_dir" ]]; then
    local ssh_perms
    ssh_perms=$(stat -f '%OLp' "$ssh_dir")
    if [[ "$ssh_perms" != "700" ]]; then
      err "SSH dir permissions: $ssh_perms (should be 700)"
      run_fix "Fix SSH dir permissions" chmod 700 "$ssh_dir"
    else
      ok "~/.ssh permissions: 700 ✔"
    fi

    # Check authorized_keys
    if [[ -f "$ssh_dir/authorized_keys" ]]; then
      local ak_count
      ak_count=$(wc -l < "$ssh_dir/authorized_keys")
      warn "authorized_keys file found with $ak_count entries — verify all are expected:"
      cat "$ssh_dir/authorized_keys" | while read -r key; do
        warn "  $(echo "$key" | awk '{print $NF}')"
      done
    else
      ok "No authorized_keys file found (expected for most desktops)"
    fi

    # Check key permissions
    for keyfile in "$ssh_dir"/id_* "$ssh_dir"/id_*; do
      [[ -f "$keyfile" ]] || continue
      echo "$keyfile" | grep -q "\.pub$" && continue
      local kperm
      kperm=$(stat -f '%OLp' "$keyfile")
      if [[ "$kperm" != "600" ]]; then
        err "SSH private key bad permissions ($kperm): $keyfile"
        run_fix "Fix SSH key permissions" chmod 600 "$keyfile"
      fi
    done
  else
    ok "No ~/.ssh directory found"
  fi

  section "Login items (user level)"
  # Using sfltool for login items on macOS 13+
  if command -v sfltool &>/dev/null; then
    info "User login items:"
    sfltool dump 2>/dev/null | grep -A2 "LoginItems" | head -20 | while read -r line; do info "  $line"; done || true
  fi
  # Fallback: check LaunchAgents-based login items
  if [[ -d "$HOME/Library/LaunchAgents" ]]; then
    local la_count
    la_count=$(find "$HOME/Library/LaunchAgents" -name "*.plist" 2>/dev/null | wc -l | tr -d ' ')
    info "User LaunchAgents count: $la_count"
  fi

  section "Gatekeeper status"
  if need_sudo "spctl --status"; then
    local gk_status
    gk_status=$(spctl --status 2>/dev/null || echo "unknown")
    if echo "$gk_status" | grep -q "enabled"; then
      ok "Gatekeeper: enabled ✔"
    else
      err "Gatekeeper is DISABLED — recommended to re-enable: sudo spctl --master-enable"
    fi
  fi

  section "Quarantine attribute on Downloads"
  local dl_no_quarantine
  # Note: macOS find does not support -xattr predicate; using xattr command instead
  dl_no_quarantine=$(find "$HOME/Downloads" -maxdepth 2 -type f \
    \( -perm -0111 -o -name "*.app" -o -name "*.dmg" -o -name "*.pkg" \) \
    2>/dev/null | while read -r f; do
      xattr -l "$f" 2>/dev/null | grep -q "com.apple.quarantine" || echo "$f"
    done | head -20 || true)
  if [[ -n "$dl_no_quarantine" ]]; then
    warn "Executables in Downloads missing quarantine attribute (may bypass Gatekeeper):"
    echo "$dl_no_quarantine" | while read -r f; do warn "  $f"; done
  else
    ok "Executables in Downloads appear properly quarantined"
  fi

  section "Kernel extensions (kexts) — non-Apple"
  local third_party_kexts
  third_party_kexts=$(kextstat 2>/dev/null | grep -v "com.apple" | awk 'NR>1{print "  " $6}' || true)
  if [[ -n "$third_party_kexts" ]]; then
    warn "Third-party kernel extensions loaded:"
    echo "$third_party_kexts" | while read -r k; do warn "$k"; done
  else
    ok "No third-party kernel extensions loaded"
  fi

  section "Keychain integrity"
  if security verify-cert -k ~/Library/Keychains/login.keychain-db >> "$LOG_FILE" 2>/dev/null; then
    ok "Login keychain accessible"
  else
    info "Could not automatically verify keychain (this is normal for user sessions)"
  fi

  section "Password-related risks"
  # Check for world-readable sensitive files
  for f in "$HOME/.netrc" "$HOME/.pgpass" "$HOME/.git-credentials"; do
    [[ -f "$f" ]] || continue
    local fp
    fp=$(stat -f '%OLp' "$f")
    if [[ "${fp: -2}" != "00" ]]; then
      err "$f has overly permissive permissions ($fp) — could expose credentials"
      run_fix "Restrict $f permissions" chmod 600 "$f"
    else
      ok "$f permissions: $fp ✔"
    fi
  done
}

# =============================================================================
# MODULE 7 — PERFORMANCE & MEMORY
# =============================================================================

module_performance() {
  should_run "performance" || return 0
  header "MODULE 7 · Performance & Memory Diagnostics"

  section "Memory pressure"
  local mem_pressure
  mem_pressure=$(memory_pressure 2>/dev/null | awk '/System-wide memory free percentage/{print $NF}' || echo "N/A")
  info "System-wide memory free: $mem_pressure"

  local vm_stats
  vm_stats=$(vm_stat 2>/dev/null)
  local pages_free pages_wired pages_active pages_inactive pages_compressed page_size
  page_size=16384  # M3 uses 16KB pages
  
  extract_pages() {
    local val
    val=$(echo "$vm_stats" | awk "/$1/{gsub(/\./,\"\",\$NF); print \$NF}" | tr -d ' \n')
    echo "${val:-0}" | grep -o '^[0-9]\+' || echo 0
  }

  pages_free=$(extract_pages 'Pages free')
  pages_wired=$(extract_pages 'Pages wired down')
  pages_active=$(extract_pages 'Pages active')
  pages_inactive=$(extract_pages 'Pages inactive')
  pages_compressed=$(extract_pages 'Pages stored in compressor')

  to_mb() { echo $(( ($1 * page_size) / 1024 / 1024 )); }

  info "Memory — Free: $(to_mb "$pages_free") MB | Active: $(to_mb "$pages_active") MB | Wired: $(to_mb "$pages_wired") MB | Compressed: $(to_mb "$pages_compressed") MB"

  local swap_raw swap_used swap_int
  swap_raw=$(sysctl -n vm.swapusage 2>/dev/null) || swap_raw=""
  swap_used=$(echo "$swap_raw" | awk '{print $6}' | tr -d 'M\n ' 2>/dev/null) || swap_used=0
  [[ "$swap_used" =~ ^[0-9]+(\.?[0-9]*)$ ]] || swap_used=0
  swap_int=$(printf '%.0f' "${swap_used:-0}" 2>/dev/null) || swap_int=0
  [[ "$swap_int" =~ ^[0-9]+$ ]] || swap_int=0
  if (( swap_int > 4096 )); then
    warn "Swap usage high: ${swap_int}MB — system under memory pressure"
  elif (( swap_int > 0 )); then
    info "Swap in use: ${swap_int}MB (some use is normal on M-series unified memory)"
  else
    ok "No swap in use — memory healthy"
  fi

  section "Top CPU consumers right now"
  info "Top 10 processes by CPU:"
  ps aux 2>/dev/null | sort -rk3 | head -11 | tail -10 | awk '{printf "  %-30s CPU:%-6s MEM:%-6s PID:%s\n", $11, $3, $4, $2}' | while read -r line; do
    info "$line"
  done

  section "Top memory consumers right now"
  info "Top 10 processes by RAM:"
  ps aux 2>/dev/null | sort -rk4 | head -11 | tail -10 | awk '{printf "  %-30s MEM:%-6s CPU:%-6s PID:%s\n", $11, $4, $3, $2}' | while read -r line; do
    info "$line"
  done

  section "Thermal state & throttling"
  if command -v powermetrics &>/dev/null && need_sudo "powermetrics thermal check"; then
    local thermal
    thermal=$(sudo powermetrics -n 1 -s cpu_power,thermal --show-process-energy 2>/dev/null | grep -i "thermal\|throttl\|temp" | head -5 || true)
    if [[ -n "$thermal" ]]; then
      info "Thermal info: $thermal"
    else
      ok "No thermal throttling detected"
    fi
  fi

  section "Spotlight indexing status"
  local mdstatus
  mdstatus=$(mdutil -as 2>/dev/null | head -5 || echo "n/a")
  info "Spotlight: $mdstatus"
  # Check if Spotlight is running high CPU
  if ps aux | grep -v grep | grep -q "mds_stores\|mdworker"; then
    info "Spotlight (mds) is running — normal after updates"
  fi
}

# =============================================================================
# MODULE 8 — CACHE & TEMP FILE CLEANUP
# =============================================================================

module_cache() {
  should_run "cache" || return 0
  header "MODULE 8 · Cache & Temporary File Cleanup"

  section "User cache size"
  local cache_size
  cache_size=$(du -sh "$HOME/Library/Caches" 2>/dev/null | cut -f1 || echo "N/A")
  info "~/Library/Caches : $cache_size"

  section "System cache"
  if need_sudo "du /Library/Caches"; then
    local sys_cache_size
    sys_cache_size=$(du -sh /Library/Caches 2>/dev/null | cut -f1 || echo "N/A")
    info "/Library/Caches  : $sys_cache_size"
  fi

  section "Clearing user caches (safe)"
  local USER_CACHE_TARGETS=(
    "$HOME/Library/Caches/com.apple.Safari"
    "$HOME/Library/Caches/CloudKit"
    "$HOME/Library/Caches/com.apple.bird"
    "$HOME/Library/Caches/com.apple.commerce"
    "$HOME/Library/Caches/com.apple.iTunes"
  )
  for cache in "${USER_CACHE_TARGETS[@]}"; do
    [[ -d "$cache" ]] || continue
    local sz
    sz=$(du -sh "$cache" 2>/dev/null | cut -f1)
    info "Cache target: $sz  $cache"
    if ! $DRY_RUN; then
      rm -rf "$cache" && fixed "Cleared: $cache ($sz)"
    else
      skip "[DRY-RUN] Would clear: $cache ($sz)"
    fi
  done

  section "DNS cache flush"
  if ! $DRY_RUN; then
    if sudo dscacheutil -flushcache 2>/dev/null && sudo killall -HUP mDNSResponder 2>/dev/null; then
      fixed "DNS cache flushed"
    else
      warn "DNS flush failed — may need sudo"
    fi
  else
    skip "[DRY-RUN] Would flush DNS cache"
  fi

  section "Font cache"
  if need_sudo "atsutil databases -remove"; then
    if ! $DRY_RUN; then
      atsutil databases -remove >> "$LOG_FILE" 2>&1 && fixed "Font cache cleared" || warn "Font cache clear failed"
    else
      skip "[DRY-RUN] Would clear font cache (atsutil databases -remove)"
    fi
  fi

  section "Xcode derived data (if exists)"
  local xcode_dd="$HOME/Library/Developer/Xcode/DerivedData"
  if [[ -d "$xcode_dd" ]]; then
    local xdd_size
    xdd_size=$(du -sh "$xcode_dd" 2>/dev/null | cut -f1)
    warn "Xcode DerivedData: $xdd_size — Consider clearing if not actively developing"
    info "To clear manually: rm -rf \"$xcode_dd\""
  fi

  section "iOS device backups"
  local backup_dir="$HOME/Library/Application Support/MobileSync/Backup"
  if [[ -d "$backup_dir" ]]; then
    local bk_size
    bk_size=$(du -sh "$backup_dir" 2>/dev/null | cut -f1)
    info "iPhone/iPad backups: $bk_size at $backup_dir"
    warn "Consider managing old device backups in Finder > Preferences > Devices"
  fi

  section "Homebrew cleanup (if installed)"
  if command -v brew &>/dev/null; then
    info "Homebrew is installed"
    if ! $DRY_RUN; then
      brew cleanup --prune=all >> "$LOG_FILE" 2>&1 && fixed "Homebrew cache cleaned" || warn "Homebrew cleanup had warnings"
    else
      skip "[DRY-RUN] Would run: brew cleanup --prune=all"
    fi
  fi

  section "npm cache (if installed)"
  if command -v npm &>/dev/null; then
    if ! $DRY_RUN; then
      npm cache clean --force >> "$LOG_FILE" 2>&1 && fixed "npm cache cleaned" || warn "npm cache clean had warnings"
    else
      skip "[DRY-RUN] Would run: npm cache clean --force"
    fi
  fi

  section "pip cache (if installed)"
  if command -v pip3 &>/dev/null; then
    local pip_cache
    pip_cache=$(pip3 cache info 2>/dev/null | awk '/Location/{print $2}')
    [[ -n "$pip_cache" ]] && info "pip cache at: $pip_cache"
  fi
}

# =============================================================================
# MODULE 9 — LOG ANALYSIS & ANOMALY DETECTION
# =============================================================================

module_logs() {
  should_run "logs" || return 0
  header "MODULE 9 · Log Analysis & Anomaly Detection"

  section "System panics"
  local panic_dir="/Library/Logs/DiagnosticReports"
  if [[ -d "$panic_dir" ]]; then
    local panics crash_count
    panics=$(find "$panic_dir" -name "*.panic" -newer /tmp 2>/dev/null | wc -l | tr -d ' \n')
    panics=$(echo "${panics:-0}" | grep -o '^[0-9]\+' || echo 0)
    
    crash_count=$(find "$panic_dir" \( -name "*.ips" -o -name "*.crash" \) 2>/dev/null | wc -l | tr -d ' \n')
    crash_count=$(echo "${crash_count:-0}" | grep -o '^[0-9]\+' || echo 0)
    if (( panics > 0 )); then
      err "Found $panics kernel panic report(s) in $panic_dir"
      find "$panic_dir" -name "*.panic" | while read -r p; do
        err "  Panic: $(basename "$p")"
      done
    else
      ok "No recent kernel panic files found"
    fi
    if (( crash_count > 20 )); then
      warn "High crash report count: $crash_count files in DiagnosticReports"
    else
      info "Crash reports: $crash_count"
    fi
  fi

  section "Recent unified log — errors (last 5 minutes)"
  local log_errors
  log_errors=$(log show --last 5m --predicate 'messageType == 17' --style compact 2>/dev/null | grep -iE "error|fault|critical|panic" | grep -v "^Filtering" | head -20 || true)
  if [[ -n "$log_errors" ]]; then
    warn "Recent system errors detected:"
    echo "$log_errors" | while read -r line; do warn "  $line"; done
  else
    ok "No critical errors in last 5 minutes of system log"
  fi

  section "Failed launchd services"
  local failed_services
  failed_services=$(launchctl list 2>/dev/null | awk '$1 != "-" && $1 != "0" && $1 != "PID" {print "  Exit(" $2 "): " $3}' | grep -v "Exit(0)" | head -30 || true)
  if [[ -n "$failed_services" ]]; then
    warn "LaunchD services with non-zero exit codes:"
    echo "$failed_services" | while read -r line; do warn "$line"; done
  else
    ok "No failed LaunchD services detected"
  fi

  section "APFS volume errors from syslog"
  local apfs_errs
  apfs_errs=$(log show --last 1h --predicate 'subsystem == "com.apple.filesystems.apfs"' --style compact 2>/dev/null | grep -iE "error|fault" | grep -v "Filtering" | head -10 || true)
  if [[ -n "$apfs_errs" ]]; then
    warn "APFS errors in last hour:"
    echo "$apfs_errs" | while read -r line; do warn "  $line"; done
  else
    ok "No APFS errors found in last hour"
  fi

  section "Hardware errors from IOKit"
  local hw_errs
  hw_errs=$(log show --last 1h --predicate 'subsystem CONTAINS "iokit"' --style compact 2>/dev/null | grep -iE "error|fault|hardware" | grep -v "Filtering" | head -10 || true)
  if [[ -n "$hw_errs" ]]; then
    warn "Hardware-related IOKit errors:"
    echo "$hw_errs" | while read -r line; do warn "  $line"; done
  else
    ok "No IOKit hardware errors in last hour"
  fi

  section "Crash log summary (last 7 days)"
  find "$HOME/Library/Logs/DiagnosticReports" -name "*.ips" -mtime -7 2>/dev/null | \
    while read -r crash; do
      local app_name
      app_name=$(basename "$crash" | cut -d_ -f1)
      info "  Crash: $app_name — $(basename "$crash")"
    done || true
}

# =============================================================================
# MODULE 10 — APPLE SILICON M3 MAX SPECIFIC CHECKS
# =============================================================================

module_asic() {
  should_run "asic" || return 0
  header "MODULE 10 · Apple Silicon M3 Max Specific Diagnostics"

  section "Chip verification"
  local cpu_brand
  cpu_brand=$(sysctl -n machdep.cpu.brand_string 2>/dev/null || echo "Unknown")
  if echo "$cpu_brand" | grep -qi "Apple"; then
    ok "Confirmed Apple Silicon: $cpu_brand"
  else
    warn "Unexpected CPU: $cpu_brand"
  fi

  section "Translation layer (x86 emulation)"
  local rosetta_running=false
  if /usr/bin/pgrep oahd &>/dev/null; then
    rosetta_running=true
    info "Rosetta 2 (oahd) is active"
    # Check which processes are running under Rosetta
    local translated
    translated=$(ps -A -o pid,comm 2>/dev/null | while read -r pid comm; do
      local atype
      atype=$(sysctl -n "sysctl.proc_translated" 2>/dev/null || true)
      [[ "$atype" == "1" ]] && echo "  PID $pid: $comm"
    done | head -10 || true)
    [[ -n "$translated" ]] && info "Under Rosetta: $translated"
  else
    ok "Rosetta 2 not active (running fully native)"
  fi

  section "Neural Engine status"
  # ANE (Apple Neural Engine) — indirectly check via ane subsystem logs
  local ane_info
  ane_info=$(log show --last 5m --predicate 'subsystem CONTAINS "ane"' --style compact 2>/dev/null | grep -v "Filtering" | head -5 || true)
  [[ -n "$ane_info" ]] && info "ANE activity: $ane_info" || ok "ANE subsystem quiet (normal)"

  section "Unified memory pressure"
  local mem_total
  mem_total=$(( $(sysctl -n hw.memsize 2>/dev/null) / 1024 / 1024 / 1024 ))
  info "Unified memory: ${mem_total} GB (shared CPU/GPU)"
  if (( mem_total >= 32 )); then
    ok "${mem_total}GB unified memory — excellent for professional workloads"
  fi

  section "Media engine (H.264/HEVC/ProRes)"
  # Check if VideoToolbox is accessible
  if system_profiler SPDisplaysDataType 2>/dev/null | grep -qi "Apple"; then
    ok "Apple GPU (integrated) detected — media engine available"
  fi

  section "Secure Enclave & T-series"
  if system_profiler SPHardwareDataType 2>/dev/null | grep -qi "Secure Enclave"; then
    ok "Secure Enclave confirmed present"
  else
    info "Could not directly verify Secure Enclave (expected on M-series Macs)"
  fi

  section "Power adapter & charging"
  local charging_info
  charging_info=$(system_profiler SPPowerDataType 2>/dev/null | grep -A3 "Charging\|Wattage\|Adapter" | head -12)
  if [[ -n "$charging_info" ]]; then
    echo "$charging_info" | while read -r line; do info "  $line"; done
  fi

  section "Thermal sensors"
  if need_sudo "powermetrics thermal"; then
    local thermal_data
    thermal_data=$(sudo powermetrics -n 1 -s thermal 2>/dev/null | grep -i "temp\|thermal\|degree" | head -10 || true)
    [[ -n "$thermal_data" ]] && echo "$thermal_data" | while read -r line; do info "  $line"; done || ok "No thermal warnings"
  fi
}

# =============================================================================
# MODULE 11 — MAINTENANCE & SYSTEM SERVICES
# =============================================================================

module_maintenance() {
  should_run "maintenance" || return 0
  header "MODULE 11 · System Maintenance & Background Services"

  section "Periodic maintenance tasks (daily/weekly/monthly)"
  for task in daily weekly monthly; do
    local last_run
    last_run=$(defaults read /var/db/com.apple.xpc.launchd/lastpid 2>/dev/null || \
               stat -f "%Sm" "/var/log/${task}.out" 2>/dev/null || echo "unknown")
    info "Last $task maintenance: $last_run"
  done

  section "Run periodic maintenance now"
  if need_sudo "periodic daily weekly monthly"; then
    if ! $DRY_RUN; then
      periodic daily weekly monthly >> "$LOG_FILE" 2>&1 && fixed "Periodic maintenance tasks executed" || warn "Periodic tasks had warnings"
    else
      skip "[DRY-RUN] Would run: periodic daily weekly monthly"
    fi
  fi

  section "Time Machine status"
  local tm_status
  tm_status=$(tmutil status 2>/dev/null | grep -i "running\|destination\|Phase" | head -5 || echo "not configured")
  info "Time Machine: $tm_status"
  if tmutil destinationinfo &>/dev/null 2>&1; then
    ok "Time Machine has a backup destination set"
  else
    warn "No Time Machine backup destination configured — backup your data!"
  fi

  section "Software update check"
  info "Checking for pending macOS updates (may take a moment)..."
  local update_list
  update_list=$(softwareupdate -l 2>/dev/null | grep '\*' | head -10 || echo "")
  if [[ -n "$update_list" ]]; then
    warn "Pending software updates:"
    echo "$update_list" | while read -r u; do warn "  $u"; done
  else
    ok "No pending software updates found"
  fi

  section "Spotlight re-index check"
  local spotlight_errors
  spotlight_errors=$(mdutil -as 2>/dev/null | grep -i "error\|off" || true)
  if [[ -n "$spotlight_errors" ]]; then
    warn "Spotlight issues: $spotlight_errors"
    if need_sudo "mdutil -E /"; then
      if ! $DRY_RUN; then
        mdutil -E / >> "$LOG_FILE" 2>&1 && fixed "Spotlight re-index triggered" || warn "Spotlight re-index command failed"
      fi
    fi
  else
    ok "Spotlight indexing looks normal"
  fi

  section "App Store receipts"
  local receipt_dir="$HOME/Library/Group Containers"
  if [[ -d "$receipt_dir" ]]; then
    local rc
    rc=$(du -sh "$receipt_dir" 2>/dev/null | cut -f1)
    info "App Store group containers: $rc"
  fi

  section "iCloud drive status"
  local icloud_dir="$HOME/Library/Mobile Documents"
  if [[ -d "$icloud_dir" ]]; then
    local icloud_size
    icloud_size=$(du -sh "$icloud_dir" 2>/dev/null | cut -f1 || echo "N/A")
    info "iCloud Drive local footprint: $icloud_size"
  fi

  section "Homebrew health (if installed)"
  if command -v brew &>/dev/null; then
    info "Homebrew doctor output:"
    brew doctor 2>&1 | head -30 | while read -r line; do
      if [[ "$line" == *"Warning"* ]]; then
        warn "  $line"
      elif [[ "$line" == *"Error"* ]]; then
        err "  $line"
      else
        info "  $line"
      fi
    done || true
  fi
}

# =============================================================================
# MODULE 12 — NVRAM & SYSTEM CONFIGURATION RESET HINTS
# =============================================================================

module_nvram() {
  should_run "nvram" || return 0
  header "MODULE 12 · NVRAM & System Configuration"

  section "NVRAM contents"
  if need_sudo "nvram -p"; then
    local nvram_out
    nvram_out=$(nvram -p 2>/dev/null || echo "")
    info "NVRAM entries:"
    echo "$nvram_out" | while read -r line; do info "  $line"; done

    # Check for boot-args anomalies
    local boot_args
    boot_args=$(nvram boot-args 2>/dev/null || echo "")
    if [[ -n "$boot_args" ]]; then
      warn "Custom boot-args detected: $boot_args"
      if echo "$boot_args" | grep -qi "kext-dev-mode\|amfi_get_out_of_my_way\|cs_enforcement_disable"; then
        err "DANGEROUS boot-args found that bypass security! Consider resetting NVRAM."
      fi
    else
      ok "No custom boot-args set"
    fi
  fi

  section "NVRAM reset instructions (informational)"
  info "To reset NVRAM on Apple Silicon Mac:"
  info "  Shut down → Hold power button until 'Loading startup options' → Release"
  info "  For M-series: NVRAM resets on every secure boot (different from Intel)"
  info "  Use: sudo nvram -c  (to clear non-Apple NVRAM variables)"

  section "System Management Controller (SMC)"
  info "On Apple Silicon, SMC equivalent is managed by the Secure Enclave"
  info "SMC reset (Apple Silicon): Shut down → Wait 30s → Power on"
  info "Signs of SMC issues: unexpected restarts, fans at max, sleep issues"

  section "Boot policy"
  if need_sudo "bputil -d"; then
    local boot_policy
    boot_policy=$(bputil -d 2>/dev/null || echo "Unable to read")
    info "Boot policy: $boot_policy"
    if echo "$boot_policy" | grep -qi "Reduced Security\|Permissive Security"; then
      warn "Boot policy is not Full Security — consider re-enabling from Recovery"
    elif echo "$boot_policy" | grep -qi "Full Security"; then
      ok "Boot policy: Full Security ✔"
    fi
  fi
}

# =============================================================================
# FINAL SUMMARY
# =============================================================================

print_summary() {
  local bar
  bar=$(printf '═%.0s' {1..70})

  log_raw ""
  log_raw "${BOLD}${CYAN}╔${bar}╗${RESET}"
  log_raw "${BOLD}${CYAN}║  📋  REPAIR SUMMARY$(printf '%*s' 51 '')║${RESET}"
  log_raw "${BOLD}${CYAN}╚${bar}╝${RESET}"
  log_raw ""
  log_raw "  ${RED}${BOLD}❌  Issues found  : $TOTAL_ISSUES${RESET}"
  log_raw "  ${GREEN}${BOLD}🔧  Auto-fixed    : $TOTAL_FIXED${RESET}"
  log_raw "  ${YELLOW}${BOLD}⚠️   Warnings      : $TOTAL_WARNINGS${RESET}"
  log_raw ""
  log_raw "  ${BOLD}Full log  :${RESET} ${CYAN}$LOG_FILE${RESET}"
  log_raw "  ${BOLD}Report    :${RESET} ${CYAN}$REPORT_FILE${RESET}"
  log_raw ""

  if (( TOTAL_ISSUES == 0 )) && (( TOTAL_WARNINGS <= 3 )); then
    log_raw "  ${GREEN}${BOLD}✅  System looks healthy. No critical issues detected.${RESET}"
  elif (( TOTAL_ISSUES > 0 )); then
    log_raw "  ${RED}${BOLD}⚠️   Action required: $TOTAL_ISSUES issue(s) need attention.${RESET}"
    log_raw "  ${YELLOW}     Review the report file for details.${RESET}"
  else
    log_raw "  ${YELLOW}${BOLD}⚠️   Minor warnings detected. Review report for details.${RESET}"
  fi
  log_raw ""
  log_raw "  ${CYAN}Run 'open $REPORT_FILE' to open the Markdown report.${RESET}"
  log_raw ""

  # Append summary to report
  REPORT_LINES+=("")
  REPORT_LINES+=("---")
  REPORT_LINES+=("## Summary")
  REPORT_LINES+=("| Metric | Count |")
  REPORT_LINES+=("| ------ | ----- |")
  REPORT_LINES+=("| ❌ Issues | $TOTAL_ISSUES |")
  REPORT_LINES+=("| 🔧 Fixed  | $TOTAL_FIXED |")
  REPORT_LINES+=("| ⚠️ Warnings | $TOTAL_WARNINGS |")
}

# =============================================================================
# MAIN ENTRY POINT
# =============================================================================

main() {
  print_banner

  # Initialise report
  REPORT_LINES+=("# mac_repair.sh — Diagnostic Report")
  REPORT_LINES+=("")
  REPORT_LINES+=("**Generated:** $(date)")
  REPORT_LINES+=("**Host:** $(hostname)")
  REPORT_LINES+=("**macOS:** $(sw_vers -productName) $(sw_vers -productVersion)")
  REPORT_LINES+=("")

  log_raw "Starting diagnostics at $(date)"
  log_raw ""

  # Run modules
  module_system_info
  module_disk
  module_launchd
  module_network
  module_prefs
  module_security
  module_performance
  module_cache
  module_logs
  module_asic
  module_maintenance
  module_nvram

  print_summary
  flush_report
}

main "$@"
